const config = $node["Set | Import Config"].json;

return [
  {
    json: {
      source_file_name: config.source_file_name,
      source_file_id: config.source_file_id,
      record_type: config.record_type,
      schema_version: config.schema_version,
      inferred_year: Number(config.inferred_year || 2026),
      extracted_item_count: items.length,
      first_item: items[0]?.json || null,
      first_5_items: items.slice(0, 5).map(item => item.json)
    }
  }
];

const output = items[0].json;

if (!output.job) {
  throw new Error(
    'Debug Summary expected output.job. Make sure this node is connected directly after the KPI normalization node.'
  );
}

return [
  {
    json: {
      ...output,
      debug_summary: {
        success: true,
        import_job_id: output.job.import_job_id,
        status: output.job.status,
        clean_record_count: output.job.clean_record_count,
        rejected_row_count: output.job.rejected_row_count,
        issue_count: output.job.issue_count,
        warning_count: output.job.warning_count,
        error_count: output.job.error_count,
        tracker_kpi_count: output.job.tracker_kpi_count,
        summary_kpi_count: output.job.summary_kpi_count,
        processed_sections: output.job.processed_sections,
        first_clean_record: output.records?.[0] || null,
        rejected_rows_sample: output.rejected_rows?.slice(0, 5) || [],
        issues_sample: output.issues?.slice(0, 10) || [],
        message: 'KPI transformation completed. No database write performed yet.'
      }
    }
  }
];

const output = items[0].json;

if (!output.job) {
  throw new Error('Missing output.job. Connect this node after the KPI normalization node or pass-through Debug Summary node.');
}

if (!Array.isArray(output.records)) {
  throw new Error('Missing output.records array.');
}

const cleanRecords = output.records.map(record => ({
  record_id: record.record_id,
  import_job_id: record.import_job_id,
  schema_version: record.schema_version,

  record_type: record.record_type,
  record_category: record.record_category,
  record_subcategory: record.record_subcategory,

  title: record.title,
  start_date: record.start_date,
  end_date: record.end_date,
  month: record.month,
  status: record.status,

  year: record.normalized_payload?.year ?? null,
  month_number: record.normalized_payload?.month_number ?? null,
  period_start: record.normalized_payload?.period_start ?? null,
  period_end: record.normalized_payload?.period_end ?? null,

  strategic_pillar: record.normalized_payload?.strategic_pillar ?? null,
  kpi_number: record.normalized_payload?.kpi_number ?? null,
  kpi_id: record.normalized_payload?.kpi_id ?? null,
  kpi_name: record.normalized_payload?.kpi_name ?? null,

  actual_value: record.normalized_payload?.actual_value ?? null,
  latest_value: record.normalized_payload?.latest_value ?? null,
  latest_value_2024: record.extra_fields?.latest_value_2024 ?? null,
  target_2025: record.normalized_payload?.target_2025 ?? null,
  gap_to_target: record.normalized_payload?.gap_to_target ?? null,

  unit: record.normalized_payload?.unit ?? null,
  calculation_type: record.normalized_payload?.calculation_type ?? null,
  value_source: record.normalized_payload?.value_source ?? null,

  fallback_used: record.extra_fields?.fallback_used ?? false,
  fallback_details: record.extra_fields?.fallback_details ?? null,
  summary_dashboard_available: record.extra_fields?.summary_dashboard_available ?? false,

  validation_status: record.validation_status,
  validation_notes: record.validation_notes,

  source_file_name: record.source_file_name,
  source_sheet: record.source_sheet,
  source_row_number: record.source_row_number
}));

const baseName = String(output.job.source_file_name || 'kpi_import')
  .replace(/\.[^.]+$/, '')
  .replace(/[^\w.-]+/g, '_');

return [
  {
    json: {
      file_type: 'clean_records',
      file_name: `${baseName}_clean_kpi_monthly_records.json`,
      data: cleanRecords
    }
  },
  {
    json: {
      file_type: 'rejected_rows',
      file_name: `${baseName}_rejected_rows.json`,
      data: output.rejected_rows || []
    }
  },
  {
    json: {
      file_type: 'issues',
      file_name: `${baseName}_import_issues.json`,
      data: output.issues || []
    }
  },
  {
    json: {
      file_type: 'full_import_payload',
      file_name: `${baseName}_full_import_payload.json`,
      data: output
    }
  }
];

const item = items[0].json;

if (item.file_type !== 'clean_records') {
  throw new Error(`Expected file_type "clean_records", received "${item.file_type}".`);
}

if (!Array.isArray(item.data)) {
  throw new Error('Expected item.data to be an array of clean KPI records.');
}

const rows = item.data;

const preferredColumns = [
  'record_id',
  'import_job_id',
  'schema_version',

  'record_type',
  'record_category',
  'record_subcategory',

  'title',
  'start_date',
  'end_date',
  'month',
  'status',

  'year',
  'month_number',
  'period_start',
  'period_end',

  'strategic_pillar',
  'kpi_number',
  'kpi_id',
  'kpi_name',

  'actual_value',
  'latest_value',
  'latest_value_2024',
  'target_2025',
  'gap_to_target',

  'unit',
  'calculation_type',
  'value_source',

  'fallback_used',
  'fallback_details',
  'summary_dashboard_available',

  'validation_status',
  'validation_notes',

  'source_file_name',
  'source_sheet',
  'source_row_number'
];

const allColumns = Array.from(
  new Set(rows.flatMap(row => Object.keys(row)))
);

const columns = [
  ...preferredColumns.filter(col => allColumns.includes(col)),
  ...allColumns.filter(col => !preferredColumns.includes(col))
];

function csvEscape(value) {
  if (value === null || value === undefined) return '';

  const s = typeof value === 'object' ? JSON.stringify(value) : String(value);

  if (/[",\n\r]/.test(s)) {
    return `"${s.replace(/"/g, '""')}"`;
  }

  return s;
}

const lines = [];

lines.push(columns.map(csvEscape).join(','));

for (const row of rows) {
  lines.push(columns.map(col => csvEscape(row[col])).join(','));
}

const csv = '\uFEFF' + lines.join('\r\n');

const baseName = String(item.file_name || 'clean_kpi_records.json')
  .replace(/\.json$/i, '')
  .replace(/[^\w.-]+/g, '_');

const fileName = `${baseName}.csv`;

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(csv, 'utf8'),
  fileName,
  'text/csv'
);

return [
  {
    json: {
      file_type: 'clean_records_csv',
      file_name: fileName,
      row_count: rows.length,
      column_count: columns.length,
      columns
    },
    binary: {
      data: binaryData
    }
  }
];

const config = $node["Set | Import Config"].json;

if (!items[0].binary?.data) {
  throw new Error('Missing binary.data from Google Drive download.');
}

const sheetNames = String(config.sheet_names_csv || '')
  .split(',')
  .map(s => s.trim())
  .filter(Boolean);

if (!sheetNames.length) {
  throw new Error('No sheet names provided in sheet_names_csv.');
}

return sheetNames.map(sheetName => ({
  json: {
    source_sheet: sheetName,
    source_file_id: config.source_file_id,
    source_file_name: config.source_file_name,
    record_type: config.record_type || 'kpi_monthly_actual',
    schema_version: config.schema_version || 'canonical-records-v1',
    year: Number(config.year || 2025)
  },
  binary: items[0].binary
}));

const config = $node["Set | Import Config"].json;

const schemaVersion = config.schema_version || 'canonical-records-v1';
const recordType = config.record_type || 'kpi_monthly_actual';
const year = Number(config.year || 2025);
const sourceFileId = config.source_file_id || null;
const sourceFileName = config.source_file_name || 'unknown_kpi_workbook';

const importJobId = `kpi_imp_${Date.now()}`;

const MONTHS = [
  { key: 'jan', label: 'Jan', month_number: 1 },
  { key: 'feb', label: 'Feb', month_number: 2 },
  { key: 'mar', label: 'Mar', month_number: 3 },
  { key: 'apr', label: 'Apr', month_number: 4 },
  { key: 'may', label: 'May', month_number: 5 },
  { key: 'jun', label: 'Jun', month_number: 6 },
  { key: 'jul', label: 'Jul', month_number: 7 },
  { key: 'aug', label: 'Aug', month_number: 8 },
  { key: 'sep', label: 'Sep', month_number: 9 },
  { key: 'oct', label: 'Oct', month_number: 10 },
  { key: 'nov', label: 'Nov', month_number: 11 },
  { key: 'dec', label: 'Dec', month_number: 12 }
];

const FORMULA_ERRORS = new Set([
  '#REF!',
  '#VALUE!',
  '#DIV/0!',
  '#NAME?',
  '#N/A',
  '#NUM!',
  '#NULL!'
]);

function clean(value) {
  if (value === null || value === undefined) return null;

  const s = String(value)
    .replace(/\u00a0/g, ' ')
    .replace(/\n/g, ' ')
    .trim()
    .replace(/\s+/g, ' ');

  if (!s) return null;

  const lower = s.toLowerCase();

  if (['-', '—', '–', 'n/a', 'na', 'null', 'undefined'].includes(lower)) {
    return null;
  }

  return s;
}

function norm(value) {
  return String(value ?? '')
    .replace(/\u00a0/g, ' ')
    .replace(/\n/g, ' ')
    .trim()
    .toLowerCase()
    .replace(/&/g, ' and ')
    .replace(/[_\-./:;()\[\]#]+/g, ' ')
    .replace(/[^\p{L}\p{N}\s]+/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function hash(input, length = 16) {
  let h = 2166136261;
  const s = String(input ?? '');

  for (let i = 0; i < s.length; i++) {
    h ^= s.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }

  const hex = (h >>> 0).toString(16).padStart(8, '0');
  return (hex + hex + hex + hex).slice(0, length);
}

function isFormulaError(value) {
  const s = clean(value);
  if (!s) return false;
  return FORMULA_ERRORS.has(s.toUpperCase());
}

function toNumberOrNull(value) {
  if (value === null || value === undefined || value === '') return null;

  if (typeof value === 'number' && Number.isFinite(value)) {
    return value;
  }

  const s = clean(value);
  if (!s) return null;
  if (isFormulaError(s)) return null;

  const normalized = s
    .replace(/,/g, '')
    .replace(/%$/, '')
    .trim();

  const n = Number(normalized);

  if (!Number.isFinite(n)) return null;

  return n;
}

function pad2(n) {
  return String(n).padStart(2, '0');
}

function periodStart(yearValue, monthNumber) {
  return `${yearValue}-${pad2(monthNumber)}-01`;
}

function periodEnd(yearValue, monthNumber) {
  const d = new Date(Date.UTC(yearValue, monthNumber, 0));
  return `${d.getUTCFullYear()}-${pad2(d.getUTCMonth() + 1)}-${pad2(d.getUTCDate())}`;
}

function fieldFromHeader(header) {
  const h = norm(header);

  const aliases = {
    strategic_pillar: [
      'strategic pillar',
      'pillar'
    ],

    kpi_number: [
      'no',
      'number',
      'kpi number',
      'kpi no'
    ],

    kpi_name: [
      'kpi',
      'kpi name',
      'metric',
      'indicator'
    ],

    latest_value_2024: [
      'latest value 2024',
      '2024 latest value',
      'latest 2024'
    ],

    latest_value: [
      'latest value',
      '2025 actual',
      'actual 2025',
      'latest actual',
      'actual'
    ],

    target_2025: [
      '2025 target',
      'target 2025',
      'target'
    ],

    gap_to_target: [
      'vs target gap',
      'gap',
      'target gap',
      'gap to target'
    ],

    status: [
      'status',
      'rag status'
    ],

    unit_type: [
      'unit type',
      'unit',
      'type'
    ]
  };

  for (const month of MONTHS) {
    if (h === month.key || h === norm(month.label)) {
      return month.key;
    }
  }

  for (const [field, list] of Object.entries(aliases)) {
    if (list.map(norm).includes(h)) return field;
  }

  return null;
}

function buildColumnMapFromHeaderValues(row) {
  const map = {};

  for (const [key, value] of Object.entries(row)) {
    const label = clean(value) || key;
    const field = fieldFromHeader(label);

    if (field && map[field] === undefined) {
      map[field] = key;
    }
  }

  return map;
}

function buildColumnMapFromKeys(row) {
  const map = {};

  for (const key of Object.keys(row)) {
    const field = fieldFromHeader(key);

    if (field && map[field] === undefined) {
      map[field] = key;
    }
  }

  return map;
}

function countMonthFields(map) {
  return MONTHS.filter(month => map?.[month.key] !== undefined).length;
}

function get(row, map, field) {
  const key = map?.[field];
  return key === undefined ? null : row[key];
}

function getEither(row, primaryMap, fallbackMap, field) {
  const primary = get(row, primaryMap, field);

  if (clean(primary) !== null) return primary;

  return get(row, fallbackMap, field);
}

function values(row) {
  return Object.values(row).map(clean).filter(Boolean);
}

function detectSectionFromMap(map) {
  if (!map) return null;

  const hasKpi = map.kpi_name !== undefined;
  const hasTarget = map.target_2025 !== undefined;
  const monthCount = countMonthFields(map);
  const hasSummaryFields =
    map.latest_value_2024 !== undefined ||
    map.latest_value !== undefined;

  if (hasKpi && monthCount >= 2 && hasTarget) {
    return 'monthly_tracker';
  }

  if (hasKpi && hasTarget && hasSummaryFields && monthCount < 2) {
    return 'summary_dashboard';
  }

  return null;
}

function detectSectionFromRowValues(row) {
  const valueMap = buildColumnMapFromHeaderValues(row);
  return {
    section: detectSectionFromMap(valueMap),
    map: valueMap
  };
}

function detectSectionFromKeys(row) {
  const keyMap = buildColumnMapFromKeys(row);
  return {
    section: detectSectionFromMap(keyMap),
    map: keyMap
  };
}

function parseUnitType(value) {
  const s = clean(value);

  if (!s) {
    return {
      unit: null,
      calculation_type: null,
      unit_raw: null
    };
  }

  const match = s.match(/^(.*?)\s*\((.*?)\)\s*$/);

  if (match) {
    return {
      unit: clean(match[1]),
      calculation_type: clean(match[2]),
      unit_raw: s
    };
  }

  return {
    unit: s,
    calculation_type: null,
    unit_raw: s
  };
}

function addIssue(issues, base, severity, issueCode, fieldName, message, originalValue = null, normalizedValue = null) {
  issues.push({
    import_job_id: importJobId,
    severity,
    issue_code: issueCode,
    field_name: fieldName,
    source_file_id: sourceFileId,
    source_file_name: sourceFileName,
    source_sheet: base.source_sheet || null,
    source_row_number: base.source_row_number || null,
    original_value: originalValue === null || originalValue === undefined ? null : String(originalValue),
    normalized_value: normalizedValue === null || normalizedValue === undefined ? null : String(normalizedValue),
    message
  });
}

function buildRawRow(row, headerRow) {
  const raw = {};

  for (const [key, value] of Object.entries(row)) {
    if (headerRow) {
      raw[clean(headerRow[key]) || key] = value ?? null;
    } else {
      raw[key] = value ?? null;
    }
  }

  return raw;
}

function makeKpiId(kpiNumber, kpiName) {
  if (kpiNumber !== null && kpiNumber !== undefined) {
    return `KPI-${String(kpiNumber).padStart(2, '0')}`;
  }

  return `KPI-${hash(kpiName, 8).toUpperCase()}`;
}

const issues = [];
const trackerRows = [];
const summaryRows = [];

let currentSection = null;
let currentMap = null;
let currentHeaderRow = null;
let currentPillar = null;
let trackerRowCounter = 0;
let summaryRowCounter = 0;

for (let i = 0; i < items.length; i++) {
  const row = items[i].json;
  const sourceRowNumber = i + 1;

  const byValues = detectSectionFromRowValues(row);
  const byKeys = detectSectionFromKeys(row);

  if (byValues.section) {
    currentSection = byValues.section;
    currentMap = byValues.map;
    currentHeaderRow = row;
    currentPillar = null;

    addIssue(
      issues,
      {
        source_sheet: currentSection === 'monthly_tracker' ? 'Monthly KPI Tracker' : 'Summary Dashboard',
        source_row_number: sourceRowNumber
      },
      'info',
      currentSection === 'monthly_tracker' ? 'tracker_header_detected' : 'summary_header_detected',
      null,
      `Detected ${currentSection} header from row values.`,
      null,
      JSON.stringify(currentMap)
    );

    continue;
  }

  if (byKeys.section) {
    currentSection = byKeys.section;
    currentMap = byKeys.map;
    currentHeaderRow = null;
    currentPillar = null;

    addIssue(
      issues,
      {
        source_sheet: currentSection === 'monthly_tracker' ? 'Monthly KPI Tracker' : 'Summary Dashboard',
        source_row_number: sourceRowNumber
      },
      'info',
      currentSection === 'monthly_tracker' ? 'tracker_detected_from_keys' : 'summary_detected_from_keys',
      null,
      `Detected ${currentSection} from extracted JSON keys.`,
      null,
      JSON.stringify(currentMap)
    );
  }

  if (!currentSection || !currentMap) {
    continue;
  }

  const keyMap = buildColumnMapFromKeys(row);

  const sourceSheet =
    currentSection === 'monthly_tracker'
      ? 'Monthly KPI Tracker'
      : 'Summary Dashboard';

  const base = {
    source_sheet: sourceSheet,
    source_row_number: sourceRowNumber
  };

  const kpiName = clean(getEither(row, currentMap, keyMap, 'kpi_name'));

  if (!kpiName) {
    continue;
  }

  if (/^overall score$/i.test(kpiName)) {
    continue;
  }

  const explicitPillar = clean(getEither(row, currentMap, keyMap, 'strategic_pillar'));
  if (explicitPillar) currentPillar = explicitPillar;

  const strategicPillar = explicitPillar || currentPillar;

  const kpiNumber = toNumberOrNull(getEither(row, currentMap, keyMap, 'kpi_number'));
  const kpiId = makeKpiId(kpiNumber, kpiName);
  const unitParsed = parseUnitType(getEither(row, currentMap, keyMap, 'unit_type'));

  const rawRow = buildRawRow(row, currentHeaderRow);

  for (const [field, label] of [
    ['latest_value_2024', 'latest value 2024'],
    ['target_2025', '2025 target'],
    ['latest_value', 'latest value / actual'],
    ['gap_to_target', 'gap to target'],
    ['status', 'status']
  ]) {
    const rawValue = getEither(row, currentMap, keyMap, field);

    if (isFormulaError(rawValue)) {
      addIssue(
        issues,
        base,
        'warning',
        'formula_error_detected',
        field,
        `Formula error detected in ${label}.`,
        rawValue,
        null
      );
    }
  }

  if (currentSection === 'monthly_tracker') {
    trackerRowCounter++;

    const monthlyActuals = {};

    for (const month of MONTHS) {
      monthlyActuals[month.key] = toNumberOrNull(getEither(row, currentMap, keyMap, month.key));
    }

    trackerRows.push({
      source_sheet: sourceSheet,
      source_row_number: sourceRowNumber,
      strategic_pillar: strategicPillar,
      kpi_number: kpiNumber,
      kpi_id: kpiId,
      kpi_name: kpiName,
      latest_value: toNumberOrNull(getEither(row, currentMap, keyMap, 'latest_value')),
      target_2025: toNumberOrNull(getEither(row, currentMap, keyMap, 'target_2025')),
      gap_to_target: toNumberOrNull(getEither(row, currentMap, keyMap, 'gap_to_target')),
      status: clean(getEither(row, currentMap, keyMap, 'status')),
      unit: unitParsed.unit,
      calculation_type: unitParsed.calculation_type,
      unit_raw: unitParsed.unit_raw,
      monthly_actuals: monthlyActuals,
      raw_row: rawRow,
      row_order: trackerRowCounter
    });
  }

  if (currentSection === 'summary_dashboard') {
    summaryRowCounter++;

    summaryRows.push({
      source_sheet: sourceSheet,
      source_row_number: sourceRowNumber,
      strategic_pillar: strategicPillar,
      kpi_number: kpiNumber,
      kpi_id: kpiId,
      kpi_name: kpiName,
      latest_value_2024: toNumberOrNull(getEither(row, currentMap, keyMap, 'latest_value_2024')),
      latest_value: toNumberOrNull(getEither(row, currentMap, keyMap, 'latest_value')),
      target_2025: toNumberOrNull(getEither(row, currentMap, keyMap, 'target_2025')),
      status: clean(getEither(row, currentMap, keyMap, 'status')),
      unit: unitParsed.unit,
      calculation_type: unitParsed.calculation_type,
      unit_raw: unitParsed.unit_raw,
      raw_row: rawRow,
      row_order: summaryRowCounter
    });
  }
}

const summaryByKpiId = {};
const summaryByName = {};

for (const row of summaryRows) {
  summaryByKpiId[row.kpi_id] = row;
  summaryByName[norm(row.kpi_name)] = row;
}

const records = [];
const rejected_rows = [];

for (const tracker of trackerRows) {
  const summary =
    summaryByKpiId[tracker.kpi_id] ||
    summaryByName[norm(tracker.kpi_name)] ||
    null;

  const fallbackDetails = {
    target_2025: false,
    latest_value: false,
    status: false,
    unit: false
  };

  let target2025 = tracker.target_2025;
  let latestValue = tracker.latest_value;
  let status = tracker.status;
  let unit = tracker.unit;
  let calculationType = tracker.calculation_type;

  if (target2025 === null && summary?.target_2025 !== null && summary?.target_2025 !== undefined) {
    target2025 = summary.target_2025;
    fallbackDetails.target_2025 = true;
  }

  if (latestValue === null && summary?.latest_value !== null && summary?.latest_value !== undefined) {
    latestValue = summary.latest_value;
    fallbackDetails.latest_value = true;
  }

  if (!status && summary?.status) {
    status = summary.status;
    fallbackDetails.status = true;
  }

  if (!unit && summary?.unit) {
    unit = summary.unit;
    calculationType = summary.calculation_type;
    fallbackDetails.unit = true;
  }

  const fallbackUsed = Object.values(fallbackDetails).some(Boolean);

  for (const month of MONTHS) {
    const actualValue = tracker.monthly_actuals[month.key];

    const validationNotes = [];

    if (!tracker.strategic_pillar) {
      validationNotes.push('Missing strategic pillar.');
    }

    if (!tracker.kpi_name) {
      validationNotes.push('Missing KPI name.');
    }

    if (target2025 === null) {
      validationNotes.push('Missing 2025 target.');
    }

    if (actualValue === null) {
      validationNotes.push('Monthly actual is blank.');
    }

    if (fallbackUsed) {
      validationNotes.push('One or more fields used Summary Dashboard fallback.');
    }

    const validationStatus = validationNotes.length
      ? 'valid_with_warnings'
      : 'valid';

    const startDate = periodStart(year, month.month_number);
    const endDate = periodEnd(year, month.month_number);

    const normalizedPayload = {
      year,
      month_number: month.month_number,
      period_start: startDate,
      period_end: endDate,
      strategic_pillar: tracker.strategic_pillar,
      kpi_number: tracker.kpi_number,
      kpi_id: tracker.kpi_id,
      kpi_name: tracker.kpi_name,
      actual_value: actualValue,
      latest_value: latestValue,
      target_2025: target2025,
      gap_to_target: tracker.gap_to_target,
      status,
      unit,
      calculation_type: calculationType,
      value_source: fallbackUsed
        ? 'monthly_tracker_with_summary_fallback'
        : 'monthly_tracker'
    };

    const extraFields = {
      fallback_used: fallbackUsed,
      fallback_details: fallbackDetails,
      summary_dashboard_available: Boolean(summary),
      summary_dashboard_source_row_number: summary?.source_row_number || null,
      latest_value_2024: summary?.latest_value_2024 ?? null,
      raw_tracker_row: tracker.raw_row,
      raw_summary_row: summary?.raw_row || null
    };

    const record = {
      record_id: `rec_${hash([
        importJobId,
        tracker.kpi_id,
        month.key,
        year
      ].join('|'), 24)}`,
      import_job_id: importJobId,
      schema_version: schemaVersion,

      record_type: recordType,
      record_category: tracker.strategic_pillar,
      record_subcategory: tracker.kpi_id,

      title: tracker.kpi_name,
      start_date: startDate,
      end_date: endDate,
      month: month.label,

      location: null,
      website: null,
      entity: null,
      ga: null,

      attendance_format: null,
      sponsoring_level: null,
      contact_person: null,
      project_owner: null,
      status,

      source_file_id: sourceFileId,
      source_file_name: sourceFileName,
      source_sheet: tracker.source_sheet,
      source_row_number: tracker.source_row_number,

      validation_status: validationStatus,
      validation_notes: validationNotes.join(' '),

      raw_row: tracker.raw_row,
      normalized_payload: normalizedPayload,
      extra_fields: extraFields
    };

    if (!record.title) {
      rejected_rows.push({
        import_job_id: importJobId,
        source_file_id: sourceFileId,
        source_file_name: sourceFileName,
        source_sheet: tracker.source_sheet,
        source_row_number: tracker.source_row_number,
        rejection_reason: 'KPI title is required.',
        errors: [
          {
            field: 'title',
            code: 'required_field_missing',
            message: 'KPI title is required.'
          }
        ],
        raw_row: tracker.raw_row
      });
    } else {
      records.push(record);
    }
  }
}

if (!trackerRows.length) {
  addIssue(
    issues,
    {
      source_sheet: 'Monthly KPI Tracker',
      source_row_number: null
    },
    'error',
    'monthly_tracker_not_detected',
    null,
    'No Monthly KPI Tracker rows were detected. Check sheet name and Extract From File settings.'
  );
}

if (!summaryRows.length) {
  addIssue(
    issues,
    {
      source_sheet: 'Summary Dashboard',
      source_row_number: null
    },
    'warning',
    'summary_dashboard_not_detected',
    null,
    'No Summary Dashboard rows were detected. Summary fallback and cross-check are unavailable.'
  );
}

const warningCount = issues.filter(issue => issue.severity === 'warning').length;
const errorCount = issues.filter(issue => issue.severity === 'error').length;

const job = {
  import_job_id: importJobId,
  schema_version: schemaVersion,
  status:
    errorCount > 0 && records.length === 0
      ? 'failed_no_clean_records'
      : warningCount || errorCount
        ? 'completed_with_issues'
        : 'completed',
  source_system: 'google_drive_xlsx_kpi_tracker',
  source_file_id: sourceFileId,
  source_file_name: sourceFileName,
  record_type: recordType,
  year,
  total_records: records.length + rejected_rows.length,
  clean_record_count: records.length,
  rejected_row_count: rejected_rows.length,
  issue_count: issues.length,
  warning_count: warningCount,
  error_count: errorCount,
  tracker_kpi_count: trackerRows.length,
  summary_kpi_count: summaryRows.length,
  processed_sections: [
    ...new Set([
      ...trackerRows.map(row => row.source_sheet),
      ...summaryRows.map(row => row.source_sheet)
    ])
  ]
};

return [
  {
    json: {
      job,
      records,
      rejected_rows,
      issues,
      tracker_rows: trackerRows,
      summary_rows: summaryRows
    }
  }
];
